  "scholars.jewish.2.bio": "بائبل کی خواب کی تعبیر یوسف (پیدائش 37-41) تمام ابراہیمی خواب کی روایات کی بنیاد ہے۔ اس کی خوابوں کی تعبیر کرنے کی صلاحیت نے مصر کو قحط سے بچایا۔",
  "scholars.jewish.2.contribution": "یوسف نے دکھایا کہ خوابوں کی تعبیر ایک خدائی تحفہ ہے۔ ان کا طریقہ: علامتوں کا مستقبل کے لیے براہ راست، عملی مفہوم ہوتا ہے۔",
  "scholars.jewish.3.bio": "فیلو آف الیگزینڈریا ایک یہودی-یونانی فلسفی تھے۔ انہوں نے خوابوں کی 3 اقسام میں فرق کیا: خدائی طور پر بھیجے گئے، روح سے پیدا ہوئے، اور مخلوط خواب۔",
  "scholars.jewish.3.contribution": "فیلو پہلے شخص تھے جنہوں نے منظم طریقے سے یونانی فلسفے کو یہودی خوابوں کی روایت کے ساتھ جوڑا۔ ان کے تین اقسام کے نظریے نے عیسائی اور اسلامی خوابوں کے علماء کو متاثر کیا۔",
  "scholars.jewish.4.bio": "جرمن چاسیڈیم کی \"کتابِ پرہیزگار\" میں خوابوں کے تفصیلی اصول شامل ہیں: آدھی رات کے فوراً بعد آنے والے خواب سچے مانے جاتے ہیں۔",
  "scholars.jewish.4.contribution": "روزمرہ کے لیے خوابوں کے عملی اصول: کب خواب دیکھنا چاہیے، برے خوابوں کو کیسے دور کیا جائے (Hatavat Chalom)، اور کن خوابوں کو سنجیدگی سے لینا چاہیے۔",
  "scholars.sonniks.0.bio": "روایتی روسی خوابوں کی تعبیر کی کتابیں (Sonniki) 18ویں صدی سے موجود ہیں۔ یہ سلاوی لوک داستانوں اور بازنطینی-آرتھوڈوکس عناصر پر مبنی ہیں۔",
  "scholars.sonniks.0.contribution": "سوننک روسی گھرانوں میں سب سے زیادہ پڑھی جانے والی حوالہ جاتی کتاب ہے۔ حروف تہجی کے مطابق ترتیب دی گئی خوابوں کی علامتیں جامع تعبیرات کے ساتھ -- عقاب سے لے کر جڑواں تک۔",
  "scholars.sonniks.1.bio": "بابا وانگا ایک بلغاریائی غیب دان تھیں۔ ان کی خوابوں کی تعبیر سلاوی تصوف اور اپنے ذاتی پیشن گوئی کے تجربے پر مبنی ہے۔ 10 لاکھ سے زیادہ لوگوں نے ان سے رجوع کیا۔",
  "scholars.sonniks.1.contribution": "ان کی خوابوں کی تشریحات علامتوں کو مستقبل کی پیشین گوئیوں سے جوڑتی ہیں۔ خاص طور پر مقبول: پانی کے خواب (تبدیلی)، خواب میں مرحومین (انتباہ)۔",
  "scholars.sonniks.2.bio": "گستاوُس ہنڈمین ملر نے \"10,000 Dreams Interpreted\" لکھی -- جو سلاوی ممالک میں دنیا کی سب سے زیادہ پڑھی جانے والی خوابوں کی تعبیر کی کتاب ہے۔",
  "scholars.sonniks.2.contribution": "حقیقت پسندانہ، علامت پر مبنی تعبیرات بغیر کسی مذہبی پس منظر کے۔ ملر کی لغت روس میں بہت سے جدید سوننکی اور آن لائن خوابوں کی تعبیر کی سائٹس کی بنیاد ہے۔",
  "scholars.sonniks.3.bio": "مائیکل ڈی نوسٹراڈیمس کے پیشن گوئی کے کاموں کی خوابوں کی تعبیر کے لیے موافقت۔ سلاوی سوننکی میں ان کی رباعیوں کو خوابوں کی علامت کی لغت کے طور پر استعمال کیا جاتا ہے۔",
  "scholars.sonniks.3.contribution": "خاص طور پر apocalyptic یا سیاسی خوابوں کی تصاویر کے لیے: جنگ، قدرتی آفات، حکمرانوں کی تبدیلی۔ نوسٹراڈیمس-سوننکی تمام روسی خوابوں کی کتابوں میں سب سے زیادہ ڈرامائی ہیں۔",
  "scholars.sonniks.4.bio": "فرائیڈ کی \"خوابوں کی تعبیر\" (1899) کی مشرقی یورپی موافقتیں عوامی شکل کے لیے۔ آسان نفسیاتی تعبیرات۔",
  "scholars.sonniks.4.contribution": "فرائیڈ کی علامت نگاری (پانی=پیدائش، اڑنا=آزادی کی خواہش) کو قابل رسائی سوننک شکل میں لاتا ہے۔ نوجوان قارئین میں مقبول جو نفسیاتی وضاحتوں کو ترجیح دیتے ہیں۔",
  "scholars.ancient.0.bio": "آرٹیمیڈورس آف ڈالڈس نے قدیم دور کی سب سے اہم خوابوں کی تعبیر کی کتاب لکھی: Oneirocritica (5 جلدیں)۔ اس نے نبوی خوابوں کو روزمرہ کے خوابوں سے ممتاز کیا۔",
  "scholars.ancient.0.contribution": "اس کے طریقہ کار نے براہ راست ابن سیرین کو متاثر کیا۔ آرٹیمیڈورس نے 1000 سے زائد افراد سے ان کے خوابوں کے بارے میں پوچھا -- جو تاریخ کی پہلی تجرباتی خوابوں کی تحقیق ہے۔",
  "scholars.ancient.1.bio": "چیسٹر بیٹی پیپرس III دنیا کی قدیم ترین خوابوں کی تعبیر کی کتاب ہے۔ اس میں 108 خوابوں کی تعبیریں ہیں۔ ٹیمپل انکیوبیشن: نبوی خواب حاصل کرنے کے لیے مندر میں سونا۔",
  "scholars.ancient.1.contribution": "مصری خوابوں کی تعبیر نے \"اچھے\" اور \"برے\" خوابوں میں فرق کیا۔ سیراپیس کے پجاری پیشہ ور خوابوں کے معبر تھے۔ ان کے نظام نے براہ راست یونان اور روم کو متاثر کیا۔",
  "scholars.ancient.2.bio": "قرون وسطی کی خوابوں کی تعبیر کی کتاب، جو غلطی سے پیغمبر دانیال سے منسوب ہے۔ 100 سے زائد لاطینی نسخے محفوظ ہیں۔",
  "scholars.ancient.2.contribution": "خوابوں کی علامتوں کی حروف تہجی کے مطابق لغت۔ یورپی لوک داستانوں کی بنیاد۔ قرون وسطی کی سب سے زیادہ وسیع پیمانے پر پھیلائی جانے والی خوابوں کی کتاب -- راہبوں سے لے کر کسانوں تک۔",
  "scholars.ancient.3.bio": "اشوربانی پال کی لائبریری سے کیونیفارم تختیاں۔ خوابوں کی تعبیروں کا منظم مجموعہ: \"اگر کوئی آدمی خواب میں اڑتا ہے -- یہ نشانی ہے...\"",
  "scholars.ancient.3.contribution": "خواب خداؤں کے پیغامات تھے۔ پیشہ ور خوابوں کے معبر (sha'ilu) انہیں شاہی دربار میں تعبیر کرتے تھے۔ انسانیت کی قدیم ترین معلوم منظم خوابوں کی تعبیر۔",
  "scholars.ancient.4.bio": "امبروسیئس میکروبیئس نے سسرو کے سومنیم سکیپیونس پر تبصرہ کیا۔ اس نے 5 اقسام کے ساتھ قدیم خوابوں کی درجہ بندی کا سب سے بااثر نظام تیار کیا۔",
  "scholars.ancient.4.contribution": "سومنیم، ویزیو، اوریکولم، انسومنیم، ویزم -- خوابوں کی ان 5 اقسام نے پورے قرون وسطی کے یورپ کو تشکیل دیا اور آج تک خوابوں کی تحقیق کو متاثر کرتی ہیں۔",
